1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	type QuoteStep = { op: "quote"; items: Item[] };
9	
10	type Damage = { itemType: string; amount: number };
11	type Incident = { cause: string; damages: Damage[] };
12	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
13	
14	type Policy = {
15	  items: Item[];
16	  insuranceSum: number;
17	  remainingCap: number;
18	};
19	
20	export type Scenario = {
21	  customer: { yearsWithMHPCO: number };
22	  steps: Array<Record<string, unknown>>;
23	};
24	
25	export type ScenarioResult = {
26	  results: Array<Record<string, unknown>>;
27	};
28	
29	const PROCESSING_FEE = 5;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUES: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const DEDUCTIBLE = 100;
50	const CAP_MULTIPLIER = 2;
51	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
52	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
53	
54	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
55	
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
59	const BLOCK_SIZE = 3;
60	const BLOCK_PREMIUM = 60;
61	
62	const groupByType = (items: Item[]): Map<string, Item[]> => {
63	  const groups = new Map<string, Item[]>();
64	  for (const item of items) {
65	    const group = groups.get(item.type) ?? [];
66	    group.push(item);
67	    groups.set(item.type, group);
68	  }
69	  return groups;
70	};
71	
72	const baseTotalForGroup = (group: Item[]): number => {
73	  const type = group[0].type;
74	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
75	    return BLOCK_PREMIUM;
76	  }
77	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
78	};
79	
80	const baseTotalFor = (items: Item[]): number => {
81	  let total = 0;
82	  for (const group of groupByType(items).values()) {
83	    total += baseTotalForGroup(group);
84	  }
85	  return total;
86	};
87	
88	const CURSED_SURCHARGE_RATE = 0.5;
89	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	const HIGH_ENCHANTMENT_THRESHOLD = 5;
91	const LOYALTY_DISCOUNT_RATE = -0.2;
92	const LOYALTY_YEARS_THRESHOLD = 2;
93	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = -0.15;
94	
95	type Customer = { yearsWithMHPCO: number };
96	
97	type QuoteContext = {
98	  items: Item[];
99	  customer: Customer;
100	  isFollowUpContract: boolean;
101	};
102	
103	type PolicyModifier = {
104	  applies: (ctx: QuoteContext) => boolean;
105	  rate: number;
106	};
107	
108	const POLICY_MODIFIERS: PolicyModifier[] = [
109	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE_RATE },
110	  {
111	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
112	    rate: LOYALTY_DISCOUNT_RATE,
113	  },
114	  { applies: (ctx) => ctx.isFollowUpContract, rate: FOLLOWUP_CONTRACT_DISCOUNT_RATE },
115	];
116	
117	const itemSurchargeRateFor = (item: Item): number => {
118	  let rate = 0;
119	  if (item.cursed) rate += CURSED_SURCHARGE_RATE;
120	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
121	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
122	  }
123	  return rate;
124	};
125	
126	const itemSurchargesFor = (items: Item[]): number =>
127	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRateFor(item), 0);
128	
129	const policyModifiersTotal = (baseTotal: number, ctx: QuoteContext): number =>
130	  POLICY_MODIFIERS.reduce(
131	    (sum, mod) => (mod.applies(ctx) ? sum + baseTotal * mod.rate : sum),
132	    0,
133	  );
134	
135	const quotePremium = (
136	  items: Item[],
137	  customer: Customer,
138	  isFollowUpContract: boolean,
139	): number => {
140	  const ctx: QuoteContext = { items, customer, isFollowUpContract };
141	  const baseTotal = baseTotalFor(items);
142	  return Math.ceil(
143	    baseTotal +
144	      itemSurchargesFor(items) +
145	      policyModifiersTotal(baseTotal, ctx) +
146	      PROCESSING_FEE,
147	  );
148	};
149	
150	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
151	
152	const insuranceSumFor = (items: Item[]): number =>
153	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
154	
155	const reimbursementFor = (item: Item, damageAmount: number): number => {
156	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
157	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
158	  }
159	  return damageAmount;
160	};
161	
162	const payoutForDamage = (item: Item, damage: Damage): number => {
163	  return Math.max(0, reimbursementFor(item, damage.amount) - DEDUCTIBLE);
164	};
165	
166	const findDamagedItem = (policy: Policy, itemType: string): Item | undefined =>
167	  policy.items.find((item) => item.type === itemType);
168	
169	const grossPayoutFor = (policy: Policy, incident: Incident): number =>
170	  incident.damages.reduce((sum, damage) => {
171	    const item = findDamagedItem(policy, damage.itemType);
172	    return item ? sum + payoutForDamage(item, damage) : sum;
173	  }, 0);
174	
175	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
176	  const payout = Math.floor(Math.min(grossPayoutFor(policy, incident), policy.remainingCap));
177	  policy.remainingCap -= payout;
178	  return { payout, remainingCap: policy.remainingCap };
179	};
180	
181	export const runScenario = (scenario: Scenario): ScenarioResult => {
182	  let quoteCount = 0;
183	  const policies: Record<number, Policy> = {};
184	  const results = scenario.steps.map((step, index) => {
185	    if ((step as { op: string }).op === "quote") {
186	      const quote = step as unknown as QuoteStep;
187	      const isFollowUp = quoteCount > 0;
188	      quoteCount += 1;
189	      const insuranceSum = insuranceSumFor(quote.items);
190	      policies[index] = {
191	        items: quote.items,
192	        insuranceSum,
193	        remainingCap: insuranceSum * CAP_MULTIPLIER,
194	      };
195	      return { premium: quotePremium(quote.items, scenario.customer, isFollowUp) };
196	    }
197	    const claim = step as unknown as ClaimStep;
198	    return processClaim(policies[claim.policy], claim.incident);
199	  });
200	  return { results };
201	};
202

